10	type QuoteStep = { op: "quote"; items: Item[] };
11	type ClaimStep = {
12	  op: "claim";
13	  policy: number;
14	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
15	};
16	type Step = QuoteStep | ClaimStep;
17	
18	type Scenario = {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	};
22	
23	type Policy = {
24	  items: Item[];
25	  remainingCap: number;
26	};
27	
28	type StepResult = { premium: number } | { payout: number; remainingCap: number };
29	
30	const CAP_MULTIPLIER = 2;
31	
32	async function readStdin(): Promise<string> {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	}
39	
40	function fail(message: string): never {
41	  console.error(message);
42	  process.exit(1);
43	}
44	
45	function validateItems(items: Item[]): void {
46	  for (const item of items) {
47	    if (!isKnownItemType(item.type)) {
48	      fail(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	}
52	
53	function processQuote(
54	  step: QuoteStep,
55	  customerYears: number,
56	  previousContracts: number,
57	  policies: Policy[],
58	): StepResult {
59	  validateItems(step.items);
60	  const premium = quote({
61	    items: step.items,
62	    customerYears,
63	    previousContracts,
64	  });
65	  policies.push({
66	    items: step.items,
67	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
68	  });
69	  return { premium };
70	}
71	
72	function validateDamages(damages: { itemType: string }[], policyItems: Item[]): void {
73	  for (const damage of damages) {
74	    if (!policyItems.some((item) => item.type === damage.itemType)) {
75	      fail(`Damaged item type not in policy: ${damage.itemType}`);
76	    }
77	  }
78	  const damageCounts = new Map<string, number>();
79	  for (const damage of damages) {
80	    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
81	  }
82	  const policyCounts = new Map<string, number>();
83	  for (const item of policyItems) {
84	    policyCounts.set(item.type, (policyCounts.get(item.type) ?? 0) + 1);
85	  }
86	  for (const [itemType, count] of damageCounts) {
87	    if (count > (policyCounts.get(itemType) ?? 0)) {
88	      fail(`More damages of type ${itemType} than policy covers`);
89	    }
90	  }
91	}
92	
93	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
94	  const policy = policies[step.policy];
95	  validateDamages(step.incident.damages, policy.items);
96	  const result = claim({
97	    items: policy.items,
98	    remainingCap: policy.remainingCap,
99	    damages: step.incident.damages,
100	  });
101	  policy.remainingCap = result.remainingCap;
102	  return result;
103	}
104	
105	async function main() {
106	  const raw = await readStdin();
107	  const scenario: Scenario = JSON.parse(raw);
108	
109	  const results: StepResult[] = [];
110	  const policies: Policy[] = [];
111	  let previousContracts = 0;
112	
113	  for (const step of scenario.steps) {
114	    if (step.op === "quote") {
115	      results.push(
116	        processQuote(step, scenario.customer.yearsWithMHPCO, previousContracts, policies),
117	      );
118	      previousContracts += 1;
119	    } else {
120	      results.push(processClaim(step, policies));
121	    }
122	  }
123	
124	  console.log(JSON.stringify({ results }));
125	}
126	
127	main().catch((err) => {
128	  console.error(err instanceof Error ? err.message : String(err));
129	  process.exit(1);
130	});
